cd /tmp/sv-82f125db84b14cc9ba0e8cb84e3326b6/moderate-version-conflicts && dotnet package list --format json 2>/dev/null | python3 -m json.tool > after-cpm-packages.json && python3 -c "
import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def pkg_map(projects):
    result = {}
    for p in projects:
        name = p['path'].split('/')[-2]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

b = pkg_map(baseline['projects'])
a = pkg_map(after['projects'])

changes = []
unchanged = []
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    bv = b.get(key, '—')
    av = a.get(key, '—')
    if bv != av:
        changes.append((key[0], key[1], bv, av))
    else:
        unchanged.append((key[0], key[1], bv))

print('=== CHANGES ===')
for proj, pkg, bv, av in changes:
    print(f'  {proj}/{pkg}: {bv} -> {av}')
print(f'\n=== UNCHANGED ({len(unchanged)} packages) ===')
for proj, pkg, v in unchanged:
    print(f'  {proj}/{pkg}: {v}')
"

